import assert from 'node:assert/strict'
import { test } from 'node:test'
import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

test('geo() with Vercel headers', () => {
  const headers = new Headers({
    'x-vercel-ip-city': 'San Francisco',
    'x-vercel-ip-country': 'US',
    'x-vercel-ip-country-region': 'CA',
    'x-vercel-ip-latitude': '37.7749',
    'x-vercel-ip-longitude': '-122.4194',
    'x-vercel-ip-timezone': 'America/Los_Angeles',
  })

  const result = geo({ headers })

  assert.equal(result.city, 'San Francisco')
  assert.equal(result.countryCode, 'US')
  assert.equal(result.country, 'United States')
  assert.equal(result.region, 'CA')
  assert.equal(result.latitude, '37.7749')
  assert.equal(result.longitude, '-122.4194')
  assert.equal(result.timezone, 'America/Los_Angeles')
})

test('geoFromHeaders() with Cloudflare fallback for countryCode', () => {
  const headers = new Headers({
    'cf-ipcountry': 'GB',
  })

  const result = geoFromHeaders(headers)

  assert.equal(result.countryCode, 'GB')
  assert.equal(result.country, 'United Kingdom')
  assert.equal(result.city, undefined)
})

test('geoFromHeaders() prefers x-vercel-ip-country over cf-ipcountry', () => {
  const headers = new Headers({
    'x-vercel-ip-country': 'DE',
    'cf-ipcountry': 'FR',
  })

  const result = geoFromHeaders(headers)

  assert.equal(result.countryCode, 'DE')
  assert.equal(result.country, 'Germany')
})

test('isInRegion() returns true for matching country code', () => {
  const result = isInRegion({ countryCode: 'US' }, ['US', 'CA', 'GB'])
  assert.equal(result, true)
})

test('isInRegion() returns false for non-matching country code', () => {
  const result = isInRegion({ countryCode: 'DE' }, ['US', 'CA', 'GB'])
  assert.equal(result, false)
})

test('isInRegion() is case-insensitive', () => {
  const result = isInRegion({ countryCode: 'us' }, ['US'])
  assert.equal(result, true)
})

test('isInRegion() returns false when countryCode is undefined', () => {
  const result = isInRegion({}, ['US', 'CA'])
  assert.equal(result, false)
})

test('geoDistance() New York to London ~5570 km', () => {
  // New York: 40.7128° N, 74.0060° W
  // London: 51.5074° N, 0.1278° W
  const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
  assert.ok(
    Math.abs(distance - 5570) < 50,
    `Expected ~5570 km but got ${distance.toFixed(0)} km`
  )
})

test('geoDistance() same point returns 0', () => {
  const distance = geoDistance('51.5074', '-0.1278', '51.5074', '-0.1278')
  assert.equal(distance, 0)
})

test('missing headers return undefined fields', () => {
  const headers = new Headers()
  const result = geo({ headers })

  assert.equal(result.city, undefined)
  assert.equal(result.country, undefined)
  assert.equal(result.countryCode, undefined)
  assert.equal(result.region, undefined)
  assert.equal(result.latitude, undefined)
  assert.equal(result.longitude, undefined)
  assert.equal(result.timezone, undefined)
})

test('country name lookup from countryCode', () => {
  const headers = new Headers({ 'x-vercel-ip-country': 'JP' })
  const result = geo({ headers })
  assert.equal(result.country, 'Japan')
})

test('country is undefined for unknown country code', () => {
  const headers = new Headers({ 'x-vercel-ip-country': 'XX' })
  const result = geo({ headers })
  assert.equal(result.countryCode, 'XX')
  assert.equal(result.country, undefined)
})

